'use strict';

// MODULES //

import isnan from '@stdlib/math-base-assert-is-nan';


// MAIN //

/**
* Replaces strided array elements equal to `NaN` with a specified scalar constant.
*
* @private
* @param {PositiveInteger} N - number of indexed elements
* @param {*} alpha - scalar constant
* @param {Object} x - input array object
* @param {Collection} x.data - input array data
* @param {Array<Function>} x.accessors - array element accessors
* @param {integer} strideX - stride length
* @param {NonNegativeInteger} offsetX - starting index
* @returns {Object} input array object
*
* @example
* import toAccessorArray from '@stdlib/array-base-to-accessor-array';
* import arraylike2object from '@stdlib/array-base-arraylike2object';
*
* var x = [ NaN, 1.0, 3.0, NaN, 4.0, 0.0, -1.0, -3.0 ];
*
* gfillNaN( x.length, 0.0, arraylike2object( toAccessorArray( x ) ), 1, 0 );
* // x => [ 0.0, 1.0, 3.0, 0.0, 4.0, 0.0, -1.0, -3.0 ]
*/
function gfillNaN( N, alpha, x, strideX, offsetX ) {
	var xbuf;
	var get;
	var set;
	var ix;
	var i;
	var v;

	// Cache reference to array data:
	xbuf = x.data;

	// Cache references to the element accessors:
	get = x.accessors[ 0 ];
	set = x.accessors[ 1 ];

	ix = offsetX;
	for ( i = 0; i < N; i++ ) {
		v = get( xbuf, ix );
		if ( isnan( v ) ) {
			set( xbuf, ix, alpha );
		}
		ix += strideX;
	}
	return x;
}


// EXPORTS //

export default gfillNaN;
