'use strict';

/**
* Replace strided array elements equal to `NaN` with a specified scalar constant.
*
* @module @stdlib/blas-ext-base-gfill-nan
*
* @example
* import gfillNaN from '@stdlib/blas-ext-base-gfill-nan';
*
* var x = [ NaN, NaN, 1.0, NaN ];
*
* gfillNaN( x.length, 0.0, x, 1 );
* // x => [ 0.0, 0.0, 1.0, 0.0 ]
*
* @example
* import gfillNaN from '@stdlib/blas-ext-base-gfill-nan';
*
* var x = [ NaN, NaN, 1.0, NaN ];
*
* gfillNaN.ndarray( x.length, 0.0, x, 1, 0 );
* // x => [ 0.0, 0.0, 1.0, 0.0 ]
*/

// MODULES //

import setReadOnly from '@stdlib/utils-define-nonenumerable-read-only-property';
import main from './main.js';
import ndarray from './ndarray.js';


// MAIN //

setReadOnly( main, 'ndarray', ndarray );


// EXPORTS //

export default main;
