'use strict';

/**
* Cumulatively test whether at least `k` elements in a strided array are truthy.
*
* @module @stdlib/blas-ext-base-gcusome
*
* @example
* import gcusome from '@stdlib/blas-ext-base-gcusome';
*
* var x = [ 0, 0, 1, 1, 1 ];
* var out = [ false, false, false, false, false ];
*
* gcusome( x.length, 2, x, 1, out, 1 );
* // out => [ false, false, false, true, true ]
*
* @example
* import gcusome from '@stdlib/blas-ext-base-gcusome';
*
* var x = [ 0, 0, 1, 1, 1 ];
* var out = [ false, false, false, false, false ];
*
* gcusome.ndarray( x.length, 2, x, 1, 0, out, 1, 0 );
* // out => [ false, false, false, true, true ]
*/

// MODULES //

import setReadOnly from '@stdlib/utils-define-nonenumerable-read-only-property';
import main from './main.js';
import ndarray from './ndarray.js';


// MAIN //

setReadOnly( main, 'ndarray', ndarray );


// EXPORTS //

export default main;
