'use strict';

// MODULES //

import isnan from '@stdlib/math-base-assert-is-nan';


// MAIN //

/**
* Replaces double-precision floating-point strided array elements equal to `NaN` with a specified scalar constant.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {number} alpha - scalar constant
* @param {Float64Array} x - input array
* @param {integer} strideX - stride length
* @param {NonNegativeInteger} offsetX - starting index
* @returns {Float64Array} input array
*
* @example
* import Float64Array from '@stdlib/array-float64';
*
* var x = new Float64Array( [ NaN, -2.0, 3.0, NaN, 5.0, -6.0 ] );
*
* dfillNaN( 6, 0.0, x, 1, 0 );
* // x => <Float64Array>[ 0.0, -2.0, 3.0, 0.0, 5.0, -6.0 ]
*/
function dfillNaN( N, alpha, x, strideX, offsetX ) {
	var ix;
	var i;

	if ( N <= 0 ) {
		return x;
	}
	ix = offsetX;
	for ( i = 0; i < N; i++ ) {
		if ( isnan( x[ ix ] ) ) {
			x[ ix ] = alpha;
		}
		ix += strideX;
	}
	return x;
}


// EXPORTS //

export default dfillNaN;
