'use strict';

/**
* Test whether at least one element in a strided array is truthy.
*
* @module @stdlib/blas-ext-base-gany
*
* @example
* import gany from '@stdlib/blas-ext-base-gany';
*
* var x = [ 0.0, 0.0, 1.0, 2.0 ];
*
* var out = gany( x.length, x, 1 );
* // returns true
*
* @example
* import gany from '@stdlib/blas-ext-base-gany';
*
* var x = [ 0.0, 0.0, 0.0, 0.0 ];
*
* var out = gany.ndarray( x.length, x, 1, 0 );
* // returns false
*/

// MODULES //

import setReadOnly from '@stdlib/utils-define-nonenumerable-read-only-property';
import main from './main.js';
import ndarray from './ndarray.js';


// MAIN //

setReadOnly( main, 'ndarray', ndarray );


// EXPORTS //

export default main;
