'use strict';

/**
* Return the index of the last falsy element in a strided array.
*
* @module @stdlib/blas-ext-base-glast-index-of-falsy
*
* @example
* import glastIndexOfFalsy from '@stdlib/blas-ext-base-glast-index-of-falsy';
*
* var x = [ 1.0, 3.0, 0.0, 2.0, 0.0, 4.0, 1.0, 3.0 ];
*
* var idx = glastIndexOfFalsy( x.length, x, 1 );
* // returns 4
*
* @example
* import glastIndexOfFalsy from '@stdlib/blas-ext-base-glast-index-of-falsy';
*
* var x = [ 1.0, 3.0, 0.0, 2.0, 0.0, 4.0, 1.0, 3.0 ];
*
* var idx = glastIndexOfFalsy.ndarray( x.length, x, 1, 0 );
* // returns 4
*/

// MODULES //

import setReadOnly from '@stdlib/utils-define-nonenumerable-read-only-property';
import main from './main.js';
import ndarray from './ndarray.js';


// MAIN //

setReadOnly( main, 'ndarray', ndarray );


// EXPORTS //

export default main;
