'use strict';

// MODULES //

import stride2offset from '@stdlib/strided-base-stride2offset';
import ndarray from './ndarray.js';


// MAIN //

/**
* Tests whether every element in a double-precision floating-point strided array is falsy.
*
* ## Notes
*
* -   The function explicitly treats `NaN` values as falsy.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {Float64Array} x - input array
* @param {integer} strideX - stride length
* @returns {boolean} boolean indicating whether all elements are falsy
*
* @example
* import Float64Array from '@stdlib/array-float64';
*
* var x = new Float64Array( [ 0.0, 0.0, 1.0, 1.0 ] );
*
* var v = dnone( x.length, x, 1 );
* // returns false
*/
function dnone( N, x, strideX ) {
	var ox = stride2offset( N, strideX );
	return ndarray( N, x, strideX, ox );
}


// EXPORTS //

export default dnone;
