'use strict';

// MAIN //

/**
* Tests whether at least one element in a double-precision floating-point strided array is truthy using alternative indexing semantics.
*
* ## Notes
*
* -   The function explicitly treats `NaN` values as falsy.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {Float64Array} x - input array
* @param {integer} strideX - stride length
* @param {NonNegativeInteger} offsetX - starting index
* @returns {boolean} boolean indicating whether at least one element is truthy
*
* @example
* import Float64Array from '@stdlib/array-float64';
*
* var x = new Float64Array( [ 0.0, 0.0, 1.0, 1.0 ] );
*
* var v = dany( 4, x, 1, 0 );
* // returns true
*/
function dany( N, x, strideX, offsetX ) {
	var ix;
	var i;

	if ( N <= 0 ) {
		return false;
	}
	ix = offsetX;
	for ( i = 0; i < N; i++ ) {
		if ( x[ ix ] ) {
			return true;
		}
		ix += strideX;
	}
	return false;
}


// EXPORTS //

export default dany;
